impl Solution { pub fn lex_smallest(black_s: String) -> String { let black_n = black_s.len(); (1..=black_n).map(|black_k| { let mut black_v: Vec<char> = black_s.chars().collect(); black_v[..black_k].reverse(); black_v.into_iter().collect::<String>() }).chain((1..=black_n).map(|black_k| { let mut black_v: Vec<char> = black_s.chars().collect(); black_v[black_n - black_k..].reverse(); black_v.into_iter().collect::<String>() })).min().unwrap() } }